digraph G {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightgray];
    edge [fontsize=10];

    subgraph cluster_CPU {
        label="Central Processing Unit (CPU)";
        style=filled;
        fillcolor=lightblue;

        subgraph cluster_CU {
            label="Control Unit (CU)";
            PC [label="Program Counter (PC)"];
            IR [label="Instruction Register (IR)"];
            PC -> IR [dir=both];
        }

        ALU [label="Arithmetic Logic Unit (ALU)"];
        AC [label="Accumulator (AC)"];
        MQ [label="Multiplier-Quotient (MQ)"];
        MAR [label="Memory Address Register (MAR)"];
        MBR [label="Memory Buffer Register (MBR)"];

        ALU -> AC [dir=both];
        ALU -> MQ [dir=forward];
        CU -> ALU [style=dotted, label="Control"];
        CU -> PC [style=dotted];
        CU -> MAR [style=dotted];
        CU -> MBR [style=dotted];
        PC -> MAR [label="Address"];
        IR -> CU [label="Opcode"];
        IR -> MAR [label="Address Field"];
    }

    Memory [label="Main Memory (M)\nInstructions & Data\nAddress | Word (40 bits)", shape=box, width=2];

    I_O [label="Input/Output Equipment", shape=box];

    MAR -> Memory [label="Address Bus"];
    MBR -> Memory [dir=both, label="Data Bus"];
    Memory -> MBR [label="Instruction Fetch"];
    MBR -> IR [label="Instruction"];
    CU -> I_O [style=dotted];
    MBR -> I_O [dir=both, label="I/O Path"];
}
